import os
import json
from typing import List, Dict, Any
from langchain.vectorstores import Chroma
from langchain.embeddings import HuggingFaceEmbeddings
from langchain.llms import OpenAI
from langchain.chains import RetrievalQA
from langchain.text_splitter import RecursiveCharacterTextSplitter
from langchain.docstore.document import Document
from langchain.prompts import PromptTemplate
import logging

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class RAGSystem:
    def __init__(self, vector_db_path: str = "chroma_db", embedding_model: str = "sentence-transformers/all-MiniLM-L6-v2"):
        self.vector_db_path = vector_db_path
        self.embeddings = HuggingFaceEmbeddings(model_name=embedding_model)
        self.vector_store = None
        self.qa_chain = None
        
    def load_documents(self, documents: List[Dict[str, str]]):
        """Load documents into vector database"""
        try:
            # Prepare documents for embedding
            docs = []
            for doc in documents:
                docs.append(Document(
                    page_content=doc.get('content', ''),
                    metadata={'source': doc.get('source', 'unknown')}
                ))
            
            # Split documents
            text_splitter = RecursiveCharacterTextSplitter(
                chunk_size=1000,
                chunk_overlap=200
            )
            split_docs = text_splitter.split_documents(docs)
            
            # Create vector store
            self.vector_store = Chroma.from_documents(
                documents=split_docs,
                embedding=self.embeddings,
                persist_directory=self.vector_db_path
            )
            
            self.vector_store.persist()
            logger.info("Documents loaded successfully")
            
        except Exception as e:
            logger.error(f"Error loading documents: {str(e)}")
            raise
    
    def initialize_qa_chain(self, llm_api_key: str, llm_model: str = "gpt-3.5-turbo"):
        """Initialize the QA chain with LLM"""
        try:
            # Initialize LLM
            llm = OpenAI(
                model_name=llm_model,
                openai_api_key=llm_api_key,
                temperature=0,
                max_tokens=1500
            )
            
            # Create custom prompt to prevent data leakage
            prompt_template = """
            You are an internal knowledge base assistant. Use only the provided context to answer questions.
            If the context doesn't contain information to answer the question, respond with: "I don't have information about that in our knowledge base."
            
            Context:
            {context}
            
            Question: {question}
            
            Answer:
            """
            
            PROMPT = PromptTemplate(
                template=prompt_template,
                input_variables=["context", "question"]
            )
            
            # Create retrieval chain
            self.qa_chain = RetrievalQA.from_chain_type(
                llm=llm,
                chain_type="stuff",
                retriever=self.vector_store.as_retriever(),
                return_source_documents=True,
                chain_type_kwargs={"prompt": PROMPT}
            )
            
            logger.info("QA chain initialized successfully")
            
        except Exception as e:
            logger.error(f"Error initializing QA chain: {str(e)}")
            raise
    
    def query(self, question: str) -> Dict[str, Any]:
        """Process user query and return answer with sources"""
        try:
            if not self.qa_chain:
                raise ValueError("QA chain not initialized. Call initialize_qa_chain first.")
            
            # Get answer
            result = self.qa_chain({"query": question})
            
            # Extract relevant information
            answer = result.get("result", "")
            source_documents = result.get("source_documents", [])
            
            # Format sources
            sources = []
            for doc in source_documents:
                sources.append({
                    "source": doc.metadata.get("source", "unknown"),
                    "content": doc.page_content[:200] + "..." if len(doc.page_content) > 200 else doc.page_content
                })
            
            return {
                "answer": answer,
                "sources": sources,
                "query": question
            }
            
        except Exception as e:
            logger.error(f"Error processing query: {str(e)}")
            return {
                "answer": "Sorry, I encountered an error processing your request.",
                "sources": [],
                "query": question
            }

